const source = $json ?? {};
const workflow = source.workflow ?? {};
const execution = source.execution ?? {};
const failure = execution.error ?? source.error ?? {};
const workflowName = String(workflow.name ?? 'Workflow desconocido').slice(0, 120);
const executionId = String(execution.id ?? 'sin-id').slice(0, 80);
const nodeName = String(execution.lastNodeExecuted ?? failure.node?.name ?? 'Nodo desconocido').slice(0, 120);
const errorType = String(failure.name ?? failure.type ?? 'Error').slice(0, 120);
const timestamp = new Date().toISOString();
const executionUrl = String(execution.url ?? '').slice(0, 500);
const subject = '[doble3d.cl] Falló Auto Post — ' + workflowName + ' — ' + executionId;
const body = [
  'Workflow: ' + workflowName,
  'Execution ID: ' + executionId,
  'Nodo: ' + nodeName,
  'Timestamp: ' + timestamp,
  'Tipo de error: ' + errorType,
  'URL de ejecución: ' + (executionUrl || 'no disponible'),
].join('\n');
return [{ json: { subject, body, workflowName, executionId, nodeName, timestamp, errorType, executionUrl } }];
